DO $$
DECLARE
  duplicate_count int;
  target_with_other_coverage int;
  lme_target_coverage int;
BEGIN
  SELECT count(*) - count(DISTINCT slug || '|' || proposicao_id_api)
  INTO duplicate_count
  FROM _seed_sapl_assembleias_completo;

  IF duplicate_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao SAPL completo: seed contem % duplicatas slug/proposicao_id_api', duplicate_count;
  END IF;

  SELECT count(*)
  INTO target_with_other_coverage
  FROM projetos_lei pl
  JOIN candidatos c ON c.id = pl.candidato_id
  JOIN _seed_sapl_assembleias_completo seed
    ON seed.slug = c.slug
   AND seed.proposicao_id_api = pl.proposicao_id_api
  WHERE pl.coverage_id IS NOT NULL
    AND pl.coverage_id NOT IN (seed.previous_coverage_id, seed.coverage_id);

  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao SAPL completo: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*)
  INTO lme_target_coverage
  FROM legislacao_mandato_executivo lme
  WHERE lme.metadata->>'coverage_id' IN (
    SELECT DISTINCT coverage_id FROM _seed_sapl_assembleias_completo
  );

  IF lme_target_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao SAPL completo: % rows LME usam coverage_id de projetos_lei alvo', lme_target_coverage;
  END IF;
END $$;

WITH target AS (
  SELECT c.id AS candidato_id, c.slug
  FROM candidatos c
  WHERE c.publicavel = true
    AND c.slug IN (SELECT DISTINCT slug FROM _seed_sapl_assembleias_completo)
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  situacao,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.situacao,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM _seed_sapl_assembleias_completo seed
JOIN target ON target.slug = seed.slug
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  situacao = EXCLUDED.situacao,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = EXCLUDED.metadata;

DO $$
DECLARE
  expected record;
  cand_id uuid;
  projetos_total int;
  complete_count int;
  old_count int;
  metadata_ok int;
  lme_total int;
  lme_target_count int;
BEGIN
  FOR expected IN
    SELECT
      slug,
      coverage_id,
      coverage_scope,
      previous_coverage_id,
      count(*)::int AS expected_count
    FROM _seed_sapl_assembleias_completo
    GROUP BY slug, coverage_id, coverage_scope, previous_coverage_id
  LOOP
    SELECT id INTO cand_id FROM candidatos WHERE slug = expected.slug AND publicavel = true;

    IF cand_id IS NULL THEN
      RAISE NOTICE '%: candidato publico ausente neste banco local/CI minimo; verificacao SAPL completo pulada', expected.slug;
      CONTINUE;
    END IF;

    SELECT count(*) INTO projetos_total FROM projetos_lei WHERE candidato_id = cand_id;
    SELECT count(*) INTO complete_count FROM projetos_lei WHERE candidato_id = cand_id AND coverage_id = expected.coverage_id;
    SELECT count(*) INTO old_count FROM projetos_lei WHERE candidato_id = cand_id AND coverage_id = expected.previous_coverage_id;
    SELECT count(*) INTO lme_total FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
    SELECT count(*) INTO lme_target_count
    FROM legislacao_mandato_executivo
    WHERE candidato_id = cand_id
      AND metadata->>'coverage_id' = expected.coverage_id;
    SELECT count(*) INTO metadata_ok
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND coverage_id = expected.coverage_id
      AND coverage_scope = expected.coverage_scope
      AND metadata->>'coverage_id' = expected.coverage_id
      AND metadata->>'coverage_scope' = expected.coverage_scope
      AND metadata->>'coverage_status' = 'completo_escopado'
      AND metadata->>'coverage_public_status' = 'parlamentar_complete'
      AND metadata->>'tabela_alvo' = 'projetos_lei'
      AND metadata->>'legislacao_mandato_executivo_mixed' = 'false'
      AND metadata->>'autoria_principal_verificada' = 'true';

    IF projetos_total <> expected.expected_count THEN
      RAISE EXCEPTION 'Pos-apply SAPL completo %: projetos_lei total esperado %, encontrado %',
        expected.slug, expected.expected_count, projetos_total;
    END IF;
    IF complete_count <> expected.expected_count THEN
      RAISE EXCEPTION 'Pos-apply SAPL completo %: rows complete esperadas %, encontradas %',
        expected.slug, expected.expected_count, complete_count;
    END IF;
    IF old_count <> 0 THEN
      RAISE EXCEPTION 'Pos-apply SAPL completo %: coverage antigo esperado 0, encontrado %',
        expected.slug, old_count;
    END IF;
    IF metadata_ok <> expected.expected_count THEN
      RAISE EXCEPTION 'Pos-apply SAPL completo %: metadata completa esperada %, encontrada %',
        expected.slug, expected.expected_count, metadata_ok;
    END IF;
    IF lme_total <> 0 THEN
      RAISE EXCEPTION 'Pos-apply SAPL completo %: legislacao_mandato_executivo esperado 0, encontrado %',
        expected.slug, lme_total;
    END IF;
    IF lme_target_count <> 0 THEN
      RAISE EXCEPTION 'Pos-apply SAPL completo %: coverage parlamentar novo nao pode existir em LME, encontrado %',
        expected.slug, lme_target_count;
    END IF;
  END LOOP;
END $$;
